export function parseArgs(argv) {
  const result = { _: [] }
  const argValues = new Map()
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (arg.includes('=')) {
      const key = arg.slice(0, arg.indexOf('='))
      const value = arg.slice(arg.indexOf('=') + 1)
      result[key] = value
      i += 1
    } else if (arg.startsWith('--')) {
      const nextArg = argv[i + 1]
      if (nextArg != null && !nextArg.startsWith('--')) {
        result[arg.slice(2)] = nextArg
        i += 2
      } else {
        result[arg.slice(2)] = true
        i += 1
      }
    } else {
      result._.push(arg)
      i += 1
    }
  }
  // Add positional args from args that were consumed as flag values
  for (const [key, val] of argValues.entries()) {
    if (val !== true) {
      result._.push(key)
      result._.push(val)
    }
  }
  return result
}

